// Rate a Deep Think
app.put('/api/deep-think/:id/rate', async (req) => {
  if (!requireAdmin(req)) return { ok: false, error: 'Admin required' }
  let data = { items: [] }
  try { data = JSON.parse(readFileSync(DEEP_THINKS_FILE, 'utf8')) } catch {}
  const dt = data.items.find(i => i.id === req.params.id)
  if (!dt) return { ok: false, error: 'Deep Think not found' }

  const { stars, agentVotes } = req.body || {}
  if (stars !== undefined) dt.rating = { stars: Math.min(5, Math.max(1, Number(stars))), ratedAt: new Date().toISOString() }
  if (agentVotes && typeof agentVotes === 'object') {
    if (!dt.agentVotes) dt.agentVotes = {}
    for (const [agentId, vote] of Object.entries(agentVotes)) {
      dt.agentVotes[agentId] = vote // 'up' or 'down'
    }
  }

  writeFileSync(DEEP_THINKS_FILE, JSON.stringify(data, null, 2))
  return { ok: true, rating: dt.rating, agentVotes: dt.agentVotes }
})

